const tender = $('load-requirements').first().json;
const profile = $('load-company-profile').first().json || {};

// Build company profile object for LLM
const companyProfile = {
  name: profile.company_name || 'Unbekanntes Unternehmen',
  capabilities_summary: profile.capabilities_summary || '',
  certifications: profile.certifications || [],
  trades: profile.trades || [],
  regions: profile.regions || [],
  service_types: profile.service_types || [],
  project_references: profile.project_references || []
};

const requirements = tender.requirements || [];

return [{ json: {
  tender_id: tender.id,
  company_profile: companyProfile,
  requirements,
  requirements_json: JSON.stringify(requirements)
} }];

const tenderId = $('load-requirements').first().json.id;
let evaluation;
try {
  const content = $json.choices[0].message.content;
  evaluation = typeof content === 'string' ? JSON.parse(content.replace(/```json|```/g, '').trim()) : content;
} catch(e) {
  evaluation = { strategic_fit_score: 0, bid_recommendation: 'needs_review', eligibility_summary: { compliant_count: 0, partial_count: 0, not_met_count: 0, blocking_issues: 0 }, eligibility_requirements: [], risks: [], clarifications: [] };
}
return [{ json: {
  id: tenderId,
  strategic_fit_score: evaluation.strategic_fit_score,
  bid_recommendation: evaluation.bid_recommendation,
  eligibility_summary: evaluation.eligibility_summary,
  eligibility_requirements: evaluation.eligibility_requirements,
  risks: evaluation.risks,
  clarifications: evaluation.clarifications,
  processing_status: 'complete'
} }];
